import { useState } from 'react';
import { useNavigate } from 'react-router-dom';

import constFlaskURL from '../../consts/constFlaskURL'

import '../../App.css';
import '../../../node_modules/bootstrap/dist/css/bootstrap.css'


function AddSing() {
    const [name_sing, setNameSing] = useState('');
    const navigate = useNavigate();

    const submitSing = async (e) => {
        e.preventDefault();

        try {
            const add_sing = await constFlaskURL.post('/sings', {
                name_sing: name_sing.name_sing
            });

            if (add_sing.status === 201){
                setNameSing('');
                navigate('/sings');
            }

        } catch (error) {
            console.log(error);
        }
    };

    return (
        <form className='container' onSubmit={submitSing}>
            <div className='mb-3'>
                <lable className='form-label'>Название дорожного знака</lable>
                <input value={name_sing} onChange={(e) => setNameSing(e.target.value)} type='text' placeholder='name_sing' className='form-control' />
            </div>
            <button type='submit' className='btn btn-primary'>
                Создать запись
            </button>
        </form>
    )

};

export default addSing;
